var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<b>어둠의 해커 9인방. 통칭 다─크 세븐.</b>","JPN":"<b>闇のハッカー9人組。通称ダークセブン。</b>","ENG":"<b>The Nine Great Hackers of Darkness. A.K.A. Daark Seven.</b>","TWN":"<b>黑暗的駭客9人幫。通稱Dark 7。</b>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<b>그들은 사회의 이면에서 암약하며 기업의 횡포와 범죄 조직의 악행을 폭로한다.</b>","JPN":"<b>彼らは社会の裏側で暗躍し、企業の横暴と犯罪組織の悪行を暴露する。</b>","ENG":"<b>They remain hidden among us as they expose the machinations of multinational conglomerates and criminal organizations.</b>","TWN":"<b>他們在社會裡暗中活躍，揭露企業的橫行與犯罪組織的惡行。</b>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<b>알파트릭스의 무차별적인 경제 침공이 갑작스럽게 중단된 것도,</b>","JPN":"<b>アルファトリックスの無差別的な経済侵攻が突然中断したのも、</b>","ENG":"<b>The wanton economic invasion of Alphatrix came to a halt,</b>","TWN":"<b>阿爾法崔克斯無差別的經濟侵略突然中斷也是,</b>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<b>사악한 악의 조직 리플레이서 신디케이트를 파멸로 몰아 넣은 것도,</b>","JPN":"<b>腹黒い悪の組織リプレイサー・シンジケートを破滅に追いやったのも、</b>","ENG":"<b>and the evil Replacer Syndicate met its doom,</b>","TWN":"<b>邪惡組織克隆集團被逼入絕境也是,</b>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<b>그 이면에는 모두 다─크 세븐의 활약이 있었다.</b>","JPN":"<b>その裏側にはいつもダークセブンの活躍があった。</b>","ENG":"<b>all thanks to the behind-the-scene efforts of Daark Seven.</b>","TWN":"<b>甚至在異界都有Dark 7活躍的身影。</b>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<b>그렇다! 다─크 세븐은 바로 왜곡된 체제에 저항하는 고독한 다─크 히어로인 것이다!</b>","JPN":"<b>そう！　ダークセブンは歪曲された体制に抵抗する孤独なダークヒーローなのである！</b>","ENG":"<b>That's right! Daark Seven is our unsung Dark Hero resisting against the nefarious system!</b>","TWN":"<b>沒錯！Dark 7正是抵抗這世間扭曲體制的黑暗英雄！</b>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"들을 때마다 쪽팔려 죽겠네, 진짜.","JPN":"本当、何回聞いても恥ずかしいわ。","ENG":"I'm so embarrassed every time I hear it.","TWN":"每次聽都覺得羞恥死了，真是的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_UI_DECK_UNIIT_SELECT"},{"id":"L12_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"무슨 소리야? 저것만큼 우리에 대해 잘 설명해 주는 코멘트가 또 어디 있어?","JPN":"そう？　私たちについてあんなきちんと説明されたコメント、他で見たことないけど。","ENG":"What do you mean? No comment explains who we are better than that!","TWN":"你在說什麼？這不是對我們最好的說明和評價嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"뭘 설명해 줘? 알파트릭스 불매 운동 게시글에 좋아요 하나 찍어 준 거?","JPN":"何が説明よ。アルファトリックス不買運動コメントに、いいね一つしかなかったくせに。","ENG":"Explains what, exactly? How we gave one \\"like\\" to the social media post boycotting Alphatrix products?","TWN":"說明什麼了？抵制阿爾法崔克斯運動的聊天串有幾個讚？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"두 개였어! 나랑 앨버트 것까지!","JPN":"二つ！　アルバートの分も含めて！","ENG":"Two likes! Mine and Albert's!","TWN":"兩個讚！我，還有亞伯特的！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"괜찮아, 매버릭. 넘버 2는 우리 조직에 들어온 지 얼마 안 되어서 그래.","JPN":"大丈夫、マーベリック。ナンバー2はこの組織に入ったばかりだから。","ENG":"It's okay, Maverick. Number 2 hasn't acclimated to our group yet, that's all.","TWN":"沒關係，麥伯利。NO.2是因為剛進組織不久，還沒適應過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"그리고 9인방이라니, 나 오기 전에도 너네 다 합쳐서 세 명밖에 없었잖아.","JPN":"それに9人組って、アタシが来る前だってアンタたち合わせて3人しかいなかったじゃない。","ENG":"And \\"Nine\\" Great Hackers? There was only three of you before I came... and it doesn't even match our name.","TWN":"還有，9人幫是什麼啦，在我來之前也只有3個人啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"크흠. 그건 일종의 TO 같은 거야. 빈 자리가 있어야 실력자들을 뽑을 수 있으니까.","JPN":"ゴホン。それはある種のTOみたいなもので、常に空席がなきゃ実力者たちを引き抜けない。","ENG":"Ahem. It's a sort of a designated vacancy. We need to leave some slots open to accept new talent.","TWN":"喔，那是某種成員編制表之類的啦，因為要為將來選拔出的人才留空位啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"그냥 멋있어 보여서 9인방으로 한 게 아니라?","JPN":"カッコいい響きだったから9人組にしたんじゃなくて？","ENG":"You didn't just randomly pick 9 because it sounded cool?","TWN":"你只是因為聽起來很帥所以叫9人幫吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"빨리 무슨 핑계라도 대 봐. 이러다 들키겠어.","JPN":"早く何か言い訳でもいいからして。このままじゃバレちゃう。","ENG":"Come on, say something. She's going to catch on.","TWN":"趕快隨便想個藉口，這樣下去會被發現的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"그런 말은 개인 채널로 해, 얼간아!","JPN":"そういう話は個人チャットですべきでしょ、バカ！","ENG":"You should send that as a DM, you moron!","TWN":"這種話在個人頻道裡說啦，笨蛋！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>GAP DARK 님이 접속하셨습니다.</color>","JPN":"<color=#ffd34c>GAP DARKさんがログインしました。</color>","ENG":"<color=#ffd34c>GAP DARK has logged in.</color>","TWN":"<color=#ffd34c>GAP DARK先生上線了。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UI_DECK_UNIIT_SELECT"},{"id":"L27_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"모두들 모였군.","JPN":"皆、集まったようだな。","ENG":"So everyone is here.","TWN":"大家都到齊了啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"리더! 기다렸어!","JPN":"リーダー！　待ってました！","ENG":"Leader! We've been waiting for you!","TWN":"老大！等你好久了！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"오늘도 멋진 무용담을 들을 수 있겠죠? 기대 중입니다!","JPN":"今日も素敵な武勇伝を聞けるんですよね？　すごく楽しみです！","ENG":"Can we hear your amazing stories again? We're looking forward to it!","TWN":"今天也可以聽到你帥氣的英雄故事吧？我很期待喔！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"여기는 내 개인적인 활약이나 뽐내자고 모이는 자리가 아냐. 그렇지 않나, 제군들.","JPN":"ここは私の個人的な活躍を自慢するために集まった場所ではない。そうだろう？","ENG":"This isn't the place for me to show off my achievements. Isn’t that right, troops?","TWN":"我們聚在這裡並不是為了公開我個人的活躍表現。不是嗎，諸君？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"우리는 어둠 속에서 세계를 수호하는 하나이자 아홉! 아홉이자 하나인 동지들이지!","JPN":"私たちは闇の中で世界を守る一つであり九つ！　九つであり一つの同志だ！","ENG":"We protect the world from the darkness. Nine for one! One for nine!","TWN":"我們是在黑暗中守護世界的9人幫！是為同樣的理想聚集在這裡的同志！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"과연 리더!","JPN":"さすがリーダー！","ENG":"Spoken like a true leader!","TWN":"不愧是老大！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"그 멘트 멋있었어요! 우리 디스코드 메인 채널에 걸어 놓죠!","JPN":"素敵なお言葉でした！　メインチャンネルに掲げましょう！","ENG":"That sounded awesome just now! We should put that on our IME channel!","TWN":"台詞好帥啊！把這句話放到我們Discord的主頻道上吧！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......저게 멋있다고?","JPN":"……あれが素敵？","ENG":"That... sounded awesome?","TWN":"……你說那個很帥？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"TYPING_LOOP"},{"id":"L37_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이 녀석들 취향은 백만 년이 지나도 이해 못할 거야, 정말.","JPN":"こいつらの好みだけは一生理解できないわね。","ENG":"I'm never going to understand what gets these nerds off. Seriously.","TWN":"說真的，就算過了一百年我也無法理解這群傢伙的喜好。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아 씨. 일과 시간에 사적인 채팅은 자제해 주십시오.","JPN":"シルビアさん。勤務時間に私的なチャットは控えてください。","ENG":"Sylvia. Please refrain from personal chatting during duty hours.","TWN":"希爾維亞小姐。工作時間請避免私人聊天。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"노는 거 아냐, 이 애늙은이야. 정보원 관리 중이라고.","JPN":"遊んでるんじゃないのよ。情報員の管理中なの！","ENG":"I'm not goofing off, you buzzkill. I'm managing my sources.","TWN":"我又沒有在玩，你這年輕的老頭，我正在管理情報員好嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"정보원 관리요?","JPN":"情報員の管理ですか？","ENG":"Your sources?","TWN":"管理情報員？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"지난번에 아줌마가 데리고 온 해커들 기억 안 나?","JPN":"この前、おばさんが連れてきたハッカーたち覚えてる？","ENG":"Remember the hackers Maria brought here the other day?","TWN":"還記得上次大嬸帶來的駭客嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그 녀석들이 앞으로 어둠의 해커 그룹 다크 세븐을 통해서 연락한다고 했거든.","JPN":"あいつらがこれから闇のハッカーグループ、ダークセブンを通じて連絡するって言ってたのよ。","ENG":"They said they'd be in touch through the hacking group called Dark Seven.","TWN":"那群傢伙說，他們以後要通過黑暗中的駭客集團Dark 7互相聯絡。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"다크 세븐......?","JPN":"ダークセブン……？","ENG":"Dark Seven?","TWN":"Dark 7……？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그...... 묘하게 기시감이 드는 이름이로군요. 어쩐지 기분이 나빠지는데요.","JPN":"……既視感がある名前ですね。なぜか不快になる。","ENG":"You know... It sounds oddly familiar. I almost feel offended.","TWN":"這……這名字有種微妙的既視感啊。不知為何有點讓人不爽。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐, 그렇긴 하지.","JPN":"まあ、確かに。","ENG":"Yeah, I know.","TWN":"對，沒錯。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"그럼 활동 결산을 시작하지.","JPN":"では、活動報告を始めよう。","ENG":"Alright, then. Let's go over our activities.","TWN":"那我們開始行動總結吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"각자 이번 달에 어떤 놀라운 성과를 이루었는지 얘기해 보게.","JPN":"各自、今月どれだけ驚くべき成果を出したか、報告するのだ。","ENG":"Let's start by sharing our amazing accomplishments this month.","TWN":"每人都說一下這個月取得了什麼驚人成果吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"우선 넘버 4인 매버릭부터.","JPN":"まずはナンバー4のマーベリックから。","ENG":"Starting with number 4, Maverick.","TWN":"先從NO.4的麥伯利開始。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"아, 전 관리국 직할 도시의 CCTV 연결망에 침투했어요.","JPN":"あ、私は管理局直轄都市のCCTVネットワークに侵入しました。","ENG":"Oh, I managed to hack into the CCTV network of the Administration Direct Control City.","TWN":"啊，我駭進了管理局直轄城市的監控器網路。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"제법인데? 그래서 뭐 쓸 만한 거라도 건졌어?","JPN":"すごいわね？　それで、使えそうなものは手に入った？","ENG":"Not bad! Did you find anything worthwhile?","TWN":"有兩下子嘛？那你找到什麼有用的東西了嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"그럼! 무단 쓰레기 투기자들을 잡아냈지!","JPN":"もちろん！　ごみの不法投棄者を捕まえた！","ENG":"Absolutely! I caught some fly-tippers!","TWN":"當然了！我抓到他們隨便亂丟垃圾！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L7_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"얼굴을 찍어다 대문짝만 하게 인쇄해서 투기 장소에 붙여 뒀으니까, 당분간 부끄러워서 얼굴도 못 들고 다닐걸?","JPN":"キャプチャーした顔を拡大して投棄場所に貼り付けておいたから、しばらくは恥ずかしくて外を歩けないと思う。","ENG":"I printed their faces and posted them all over town. I bet they'll be so ashamed that they'll have to keep their faces hidden!","TWN":"我把他們的臉拍下來，印成跟門一樣大的大小，然後貼到他們亂丟垃圾的地方，這段時間他們應該會丟臉得抬不起頭吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"오오...... 굉장하군! 놀라워!","JPN":"おぉ……素晴らしい！","ENG":"Ooh... Impressive! That's amazing!","TWN":"哦哦……了不起！太驚人了！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"기껏 침투해서 한 게 그거야? 좀 더 생산적인 일도 가능하잖아?","JPN":"侵入までして、たったそれだけ？　もう少し生産的なことも可能じゃない？","ENG":"That's all you got from that? Couldn't you have done something a little more productive?","TWN":"大費周章地駭進去，結果就這樣？難道不能做點有建設性的事情嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"무슨 소리야, 넘버 2.","JPN":"ナンバー2、どういうこと？","ENG":"Don't be absurd, number 2.","TWN":"你在說什麼，NO.2."},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"거리를 깨끗하게 만드는 것보다 더 생산적인 일이 어디 있다고.","JPN":"道を綺麗にすることより、生産的なことなんてあるわけない。","ENG":"There's nothing more productive than keeping our streets clean.","TWN":"有什麼事情比保持街道乾淨更有建設性了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"넘버 2가 이해해 줘. 매버릭 녀석은 예전부터 정말 중요한 일이 뭔지 구분을 못했거든.","JPN":"マーベリックは昔から本当に重要なことが何なのか、ちゃんと区別できないの。\\nだから、ナンバー2も理解してあげて。","ENG":"Cut him a little slack, number 2. Maverick was never good at realizing what's most important.","TWN":"NO.2，你就理解一下吧。麥伯利這傢伙從來分不清什麼是真正重要的事情。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"그래, 넌 좀 제대로 된 생각을 할 줄......","JPN":"そっか、アンタは少しまともだと思ってたから……","ENG":"Good to know at least you're on the...","TWN":"哦哦，你竟然會有正常的想法，我都……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"기왕 잡으려면 분리 수거 안 하는 녀석들도 혼쭐을 내 줬어야지!","JPN":"いっそ捕まえるなら、ごみの分別をしてないやつらも捕まれば良かったんじゃない？","ENG":"He should've punished the jerks who don't recycle as well!","TWN":"既然都要抓了，那就要把那些不做垃圾分類的傢伙也一起收拾掉啊！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"......모르는구만.","JPN":"……呆れたわ。","ENG":"...wrong track.","TWN":"……不知道呢。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"아차! 역시 앨버트 말이 맞아. 다음에는 잊지 않겠어!","JPN":"あちゃ～、さすがアルバート。今度は絶対に忘れない！","ENG":"Oh, oops! You're right, Albert. I won't forget next time!","TWN":"哎呀！果然還是亞伯特說的沒錯。下次我不會再忘了！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"그럼 넘버 3, 앨버트 자네는 어땠나?","JPN":"では次はナンバー3のアルバート。","ENG":"How about number 3? Albert?","TWN":"那麼NO.3,亞伯特你呢？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"전 오래 전부터 준비해 왔던 계획을 마침내 성사시켰습니다.","JPN":"私は昔から準備していた計画を実行することができました。","ENG":"I've finally accomplished something I've been planning for a long time.","TWN":"我準備了很久的計畫前不久終於成功了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"바로 스위스 은행의 전산망을 뚫는 것 말이죠.","JPN":"スイス銀行のコンピューターネットワークをハッキングする計画です。","ENG":"I finally got through to the Swiss banks' network.","TWN":"那就是突破瑞士銀行的電腦網路。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"뭐야? 정말 해낸 거야?","JPN":"えっ？　できたの？","ENG":"What? You really pulled that off?","TWN":"什麼？真的嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"꽤 하네? 보안으로 따지면 관리국이랑도 맞먹을 만한 곳이잖아?","JPN":"やるわね？　セキュリティで言えば、管理局と張り合うくらいの場所じゃない。","ENG":"That's pretty impressive. The security for those banks are almost as robust as the Administration itself.","TWN":"挺厲害的啊？那邊的資安水準不是可以和管理局匹敵嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"그래서 어떻게 했는데? 비밀 거래 리스트라도 손에 넣었어?","JPN":"それで、どうなったの？　秘密取引リストでも手に入った？","ENG":"So what did you do with that? Did you find a secret roster of account holders with dirty money?","TWN":"所以你做了什麼？有拿到什麼秘密交易清單嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"계좌를 새로 만들었지.","JPN":"口座を新規開設した。","ENG":"I created a new account.","TWN":"我開了一個新的帳戶。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"크으! 너처럼 제대로 된 소득도 없는 녀석에게 계좌를 만들어 주다니!","JPN":"くぅ～！　ちゃんとした所得もないやつの口座を作ったとは！","ENG":"Ah! They had to make you an account when you hardly have any income!","TWN":"哇啊！他們居然會給你這種沒有收入的傢伙開戶！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"굴욕적이겠어!","JPN":"最高の屈辱！","ENG":"That must have broken their spirits!","TWN":"他們一定會感到非常屈辱吧！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"스위스 은행에 굴욕을 선사했군!","JPN":"スイス銀行に屈辱を与えたな！","ENG":"You've put the Swiss banks to shame!","TWN":"瑞士銀行前所未有的屈辱！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L35_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"그 말대로야. 돈이 넘쳐나는 부자들만 손님으로 받던 은행이 나같이 직장도 없는 청년 백수를 고객 명단에 올리다니......","JPN":"山ほどの大金を手にする大富豪を相手にしてる銀行が、私みたいな職場もない若者フリーターを顧客リストに加えるとは……","ENG":"Exactly. The bank that had no one but rich people as its customers ended up including a bum like me on their roster of clients...","TWN":"說的沒錯。一家只接受富人的銀行竟然會把我這種沒有工作的青年列入顧客名單……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"뒤늦게 알아차렸을 때 얼마나 큰 패배감을 느낄지 상상만 해도 무시무시해!","JPN":"後々気付いた時に、どれほどの敗北感を覚えるか……想像しただけでもすごい達成感！","ENG":"By the time they realize what happened, they'll feel such a great sense of shame! Scary stuff!","TWN":"他們事後注意到時會有多大的挫敗感，想想都覺得可怕！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"......네 인생이 무시무시하다, 야.","JPN":"……あんたたちの人生の方がすごいわ。","ENG":"Your cluelessness is scaring me more.","TWN":"……你的人生才讓人覺得可怕啦。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"무서운 짓을 저질렀군......","JPN":"恐ろしいことをしたな……","ENG":"That is most egregious...","TWN":"你幹了相當可怕的事情啊……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"넘버 3. 자네를 승격시키는 안건은 좀 더 고민해 봐야겠어.","JPN":"ナンバー3、君を昇格させる件は少し考えさせてもらおう。","ENG":"Number 3, I'll have to defer the decision to promote you a little longer.","TWN":"NO.3，你晉升的事情，看來我得再考慮一下了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"괜찮습니다. 저도 이번만큼은 선을 넘은 게 아닌가 싶은 생각을 했으니까요.","JPN":"大丈夫です。私も今回の件は少しやり過ぎた感があったので。","ENG":"It's okay. I've been wondering if I've crossed the line this time as well.","TWN":"沒關係，我也覺得這次有點太超過了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"잠시 자숙의 시간을 가지는 것도 좋겠죠.","JPN":"しばらく、自粛するのも悪くありません。","ENG":"I could use some time to put things into perspective.","TWN":"稍微反省一下也不錯。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"돌겠네, 진짜......","JPN":"こっちがおかしくなりそう。","ENG":"You've got to be kidding me...","TWN":"真是瘋了……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"이제 우리 조직의 넘버 2, 사이버 캣의 차례로군.","JPN":"それじゃ、ナンバー2。サイバーキャットの番だ。","ENG":"Now, our number 2. Cyber Cat's turn.","TWN":"現在輪到我們組織的NO.2，賽博貓了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......이해를 못하겠군요. 다섯 살 때 만든 닉네임을 왜 아직도 고집하는 겁니까?","JPN":"……理解できません。5歳の時に作ったニックネームにいまだ固執しているとは。","ENG":"I don't get it. Why do you insist on using the nickname you made up when you were five?","TWN":"……真是令人無法理解。這個暱稱是妳五歲時取的吧，妳為什麼會這麼執著？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이래서야 익명의 의미가 없는 것 같은데요.","JPN":"これでは匿名の意味がないのでは？","ENG":"That kind of defeats the purpose of anonymity.","TWN":"這樣匿名不就沒有意義了嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"시끄러워. 이건 내 정체성이야.","JPN":"うるさいわね。これは私のアイデンティティなの。","ENG":"Shut it. This is who I am.","TWN":"吵死了。這就是我的真實面目。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"자...... 어디 보자, 이 날을 대비해 깜짝 놀랄 사건을 준비해 뒀지. 후후훗.","JPN":"どれどれ……この日に備えてサプライズを準備しておいたのよね～ふふふっ。","ENG":"Now... Let's see. I've prepared something special for this day. Heh heh heh.","TWN":"來……讓我看看，為了今天我可是準備了一個超級驚人的事件呢，呵呵呵。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"얌전히 넘버 1 타이틀을 내놓을 준비나 하고 있으라고.","JPN":"おとなしくナンバー1の座を明け渡す準備をしてなさい。","ENG":"Get ready to give up your title as number 1.","TWN":"你就準備乖乖讓出NO.1的頭銜吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"말씀하신 거랑 다르게 죽이 잘 맞는 것 같습니다. 정신연령이 비슷해서인가요?","JPN":"言葉とは裏腹に、気が合うようですね。精神年齢が同じくらいなのでしょうか？","ENG":"Despite what you've said about them, you seem to be quite compatible with the group. I guess it's because you're all just nerds after all?","TWN":"與妳說的不同，它似乎特別適合妳呢。是因為心理年齡差不多嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"시끄러워!","JPN":"うるさいわね！","ENG":"Shut up!","TWN":"吵死了！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"나야 일이 일이다 보니까 워낙 많긴 하지.","JPN":"アタシはこれが仕事だから、結構あるわよ。","ENG":"I've done plenty, given the nature of my job.","TWN":"我幹的事情實在太多了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"굳이 그 중에 하나 꼽으라면...... 그로니아 반군 중 제일 세력이 큰 녀석들의 거점을 알아낸 것 정도?","JPN":"その中で一つ選ぶとしたら……グロニア反乱軍の中で最も勢力が大きいやつらの拠点を突き止めたってことかしら？","ENG":"If I had to pick one for this month... I guess it would be locating the largest insurgency faction in Gronia?","TWN":"如果非要我挑一個的話……像是找出了葛羅尼亞叛軍中最大勢力的據點之類的？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"전략 위성만으로는 찾기 어려워서 놈들이 만들어 둔 인트라넷까지 뚫고 들어가는 수고가 있었지만, 정확하게 알아냈지.","JPN":"戦略衛星システムだけじゃ探せないから、やつらが作ったイントラネットを突破する必要があったけど、正確な場所を突き止めたわ。","ENG":"It was difficult to track them down with just the strategic satellite. So I had to penetrate their intranet as well, but I managed to pinpoint them.","TWN":"因為光靠戰略衛星很難找到，所以我費了很大力氣駭進他們的網路，最終準確找到了他們的位置。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"이거 한 방이면 지긋지긋한 반군 잔당들의 뿌리를 뽑을 수 있을 거야!","JPN":"これでしつこい反乱軍の残党の根っこを、一気に抜けるはず！","ENG":"This one shot should be enough to uproot those scumbags once and for all!","TWN":"現在可以將煩人的叛軍殘黨一網打盡了！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"그렇군요.","JPN":"そうですか。","ENG":"I see.","TWN":"這樣喔。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"알겠어.","JPN":"そう。","ENG":"Got it.","TWN":"知道了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"잠깐! 왜 전부 그렇게 시큰둥한 반응들인데?","JPN":"ちょっと！　何よ、その微妙な反応は？","ENG":"Hang on! What's with the lack of enthusiasm?","TWN":"等一下！為什麼你們的反應這麼冷淡？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"하지만 전쟁은 얘기만 들어도 무서운걸요.","JPN":"しかし、戦争はとても怖い。","ENG":"I'm scared of war. Even just talking about it.","TWN":"因為戰爭之類的，光聽就覺得很可怕啊。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"맞아. 나는 피만 봐도 경기를 일으키는 사람이라고.","JPN":"そうそう。私は血を見ただけでも失神しちゃうから。","ENG":"Ditto. I freak out even when I catch a glimpse of blood.","TWN":"就是啊，我是那種一看見血就會頭暈的人呢。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"다음은 나인가?","JPN":"次は私か？","ENG":"Am I next?","TWN":"換我了嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"쳇. 그래. 당신 차례야.","JPN":"ちっ、そうね。あなたの番よ。","ENG":"Hmpf. Yeah, your turn.","TWN":"切。對，該你了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"넘버 1이라고 자부할 정도니 분명 대단한 일을 벌였겠지?","JPN":"ナンバー1っていうくらいだから、アタシたちよりもすごいんでしょうね？","ENG":"You'd better have something really impressive since you call yourself number 1.","TWN":"既然敢自稱NO.1，那肯定做了什麼不得了的事情吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"미리 말해두는데 저 녀석들처럼 시시한 일을 자랑이라고 떠벌렸다간 엉덩이를 걷어 차 줄거야.","JPN":"言っておくけど、あいつらみたいなつまんないこと話し始めたら、蹴っ飛ばすわよ。","ENG":"And let me warn you, if it's something lame like those guys, I'm going to kick your butt.","TWN":"先說好，如果你像那兩個傢伙一樣，把一些無聊的事情誇大其詞，信不信我會踢爛你的屁股。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"그렇다면 직접 듣고 판단하는 게 좋겠군.","JPN":"そしたら、直接聞いて判断すればいい。","ENG":"You'd better hear it yourself first.","TWN":"那你就親自聽聽看吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"나는 이번에 관리국의 중추에 들어갔다네.","JPN":"私は今回、管理局の中枢に侵入した。","ENG":"I tapped into the Administration's heart this time.","TWN":"我這次駭進了管理局的中樞。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"관리국의 중추? 메인 네트워크 말이야?","JPN":"管理局の中枢？　メインネットワークのこと？","ENG":"The Administration's heart? You mean their main network?","TWN":"管理局中樞？你是指主網嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"말도 안 돼...... 거긴 외부에서 접근하는 게 물리적으로 불가능한데......?","JPN":"ウソでしょ……そこは外部からアクセスするのは物理的に不可能なはず……","ENG":"No way... It's physically impossible to access it from the outside!","TWN":"不可能……從外部接近那裡……物理意義上行不通的吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"맞아, 하지만 그런 불가능한 일을 가능하게 만드는 것이 진정한 해커의 실력이라고 할 수 있겠지.","JPN":"そうだ。しかし、不可能なことを可能にするのが真のハッカーの実力と言えるだろう。","ENG":"Yes, but it's the hacker's job to make the impossible possible.","TWN":"沒錯，但是將不可能化為可能才是真正的駭客。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"내 앞을 가로막는 수많은 보안 체계와 추적을 모두 돌파해서 마침내 내가 손에 넣은 것은......","JPN":"行く手を阻む多くのセキュリティシステムと追跡を突破し、私が手にしたものは……","ENG":"After penetrating through countless security protocols and firewalls, I finally got...","TWN":"突破了無數防火牆和追蹤，最終，我拿到了……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"마, 마침내 뭐?! 뜸들이지 말고 어서 말해!","JPN":"もったいぶらずに早く言いなさいよ！","ENG":"W-what did you get?! Stop stalling and say it!","TWN":"拿，拿到了什麼？！別賣關子了，快說！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"전설의 편의점! 아포칼립스 관리국 본점의 상품 매출 순위를 손에 넣었네!","JPN":"伝説のコンビニ！　アポカリプス管理局本店の商品売上ランキングを手に入れたのだ！","ENG":"The legendary convenience store, Apocalypse! I got the sales ranks of its flagship store at the Administration!","TWN":"我拿到了傳說中的便利商店！啟示錄便利商店管理局總店的銷售排名！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"뭐?! 정말로?!","JPN":"えっ？　本当に？","ENG":"What?! Really?!","TWN":"什麼？！真的？！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"......아니, 뭐? 정말로? 거기까지 들어가서 겨우???","JPN":"……いや、そこまで入っていって、そんなものを？","ENG":"Huh? What? Are you serious? That's all you grabbed after all the trouble it took to get in there?","TWN":"……等等，什麼？真的？就這樣？？？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"역시 리더! 굉장합니다!","JPN":"さすがリーダー！　すごい！","ENG":"You are indeed worthy of being our leader! That's amazing!","TWN":"不愧是老大！太厲害了！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"굉장해?! 저 바보짓의 어디가?!","JPN":"すごい？　売上ランキングが！？","ENG":"Amazing?! What's amazing at all about that stupid stunt?","TWN":"厲害？！這種蠢事哪裡厲害了？！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"우리가 엄두도 못 내는 일을 태연하게 해내셨잖아!","JPN":"私たちができないことを、平然とやってのけたじゃないか！","ENG":"The leader managed to pull off something we wouldn't dare with such finesse,","TWN":"不愧是老大，輕易就做到了我們做不到的事！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"게다가 굳이 사소한 정보를 빼돌려서 자신의 대범함을 드러내시다니!","JPN":"それに寛大さすら感じます！　数多く存在する情報からあえて取るに足らないものを選んでくるとは！","ENG":"intentionally stealing the most petty data to show boldness!","TWN":"而且特意去竊取這種瑣碎資訊，更彰顯了老大的度量！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"그 점에 동경하게 되어 버려! 평생 따르겠습니다, 넘버 1!","JPN":"憧れます！　一生ついていきます、ナンバー1！","ENG":"I can't help but admire the leader for that! I will follow you all my life, number 1!","TWN":"太讓人熱血沸騰了！我一輩子都跟隨您的，NO.1。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"저도 같은 생각입니다, 넘버 1!","JPN":"私もです、ナンバー1！","ENG":"Likewise, number 1!","TWN":"我也是，NO.1!"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"후우...... 나의 깊은 의도를 알아줘서 기쁘군.","JPN":"ふぅ……私の深い意図を汲み取ってくれるとは嬉しいよ。","ENG":"Phew... Thank you for understanding my deep intent.","TWN":"呵……我很高興你們能理解我的深意。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"역시 자네들은 우리 다--크 세븐의 일원으로 부족함이 없네.","JPN":"やはり君たちはダークセブンの一員に相応しい。","ENG":"You lot are surely worthy members of Daark Seven.","TWN":"果然你們作為Dark 7的一員是無可挑剔的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"기......","JPN":"ま……","ENG":"Wait...","TWN":"等……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"기다려! 이런 얼간이 같은 편파 판정은 납득 못해!","JPN":"待ってよ！　そんなバカみたいな不公平な判定、納得できない！","ENG":"Wait! I won't accept this idiotic, biased judgement!","TWN":"等等！我不認同這種不公正的結果！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"정정당당한 승부에 불복하다니 실망이군.","JPN":"正々堂々とした勝負に対して異議を唱えるとは失望したな。","ENG":"I'm disappointed you won't concede to the results of this fair competition.","TWN":"居然對公平公正的勝負不服氣，我太失望了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"의미 없는 항의를 하기보다 실력을 키워서 다음 기회를 노리는 것이......","JPN":"意味のない抗議をするより、実力を鍛えて次の機会を狙う方が……","ENG":"Rather than filing an meaningless complaint, perhaps you should build your strength and try again later—","TWN":"與其進行無意義的抗議，不如好好培養實力爭取下次……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"잠깐, 기다리게 손님이 왔나 보군.","JPN":"あっ、客人が来たようだ。","ENG":"Hang on a second. I think I've got some guests.","TWN":"等一下，看來有客人來了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BELL"},{"id":"L7_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"찾았다! 꼼짝 마라!","JPN":"見つけたわよ！　動かないで！","ENG":"Got you! Freeze!","TWN":"找到了！不要動！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"어둠의 해커, 통칭 머신 갑 다크!","JPN":"闇のハッカー、通称マシーン-甲-ダーク！","ENG":"Hacker of Darkness, a.k.a. Machine G.A.P. Dark!","TWN":"黑暗中的駭客，統稱G·A·P Dark！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"당신을 정보통신법 위반 현행범으로 체포한다!!","JPN":"情報通信法違反の現行犯で逮捕する！","ENG":"You are under arrest for the violation of the Telecommunications Act!","TWN":"我以違反資訊通信法的罪名逮捕你！！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"아, 아니 경찰이 어떻게 여길!!","JPN":"あっ、いや。警察がどうやってここを！？","ENG":"H-how did the police get here?!","TWN":"警察是怎麼找到這裡的！！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"그, 그보다 나는 사회의 정의와 질서를 위해 노력하는 어둠의 히어로......","JPN":"そ、そんなことより私は社会の正義と秩序のため努める闇のヒーロー……","ENG":"B-but I'm the dark hero who strives for social justice and order...","TWN":"我，我可是守護社會正義和秩序的黑暗英雄……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그만! 진술은 서에서 듣기로 하겠어!","JPN":"ストップ！　供述は署で聞かせてもらうわ！","ENG":"Enough! You can give your statement at the precinct!","TWN":"夠了！有什麼話到法庭去說！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"......그런데 경정님.","JPN":"……警視様。","ENG":"By the way, Major...","TWN":"不過，警正……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이거, 왠지 그 코핀 컴퍼니의 사장님이랑 묘하게 닮은 것 같지 않아요?","JPN":"コフィンカンパニーの社長と似ていませんか？","ENG":"Doesn't this hacker look oddly similar to the Coffin Company's boss?","TWN":"這東西，是不是有點像科芬公司的老闆？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"뭐? 그러고 보니 그런 것 같기도 한데......","JPN":"えっ？　そういえば、そんな気もしなくもないですね……","ENG":"Huh? Now that you mention it, I think I see the resemblance...","TWN":"什麼？經妳這麼一說確實……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아, 여길 보세요. 조금 전까지 누군가와 통신을 하고 있었나 봐요.","JPN":"あっ、ここを見てください。今さっきまで誰かと通信していたようです。","ENG":"Oh, and look here. Our suspect must have been communicating with someone just till now.","TWN":"啊，來看看這個。看來它剛才在跟誰通訊啊。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"누가 연결되어 있는 거지......?","JPN":"誰がアクセスを……？","ENG":"Who's connected?","TWN":"會是誰呢……？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"휴! 다행이야! 자칫하면 들킬 뻔했잖아?","JPN":"ふぅ！　あと少しでバレるところだった。","ENG":"Whew! Thank goodness! We almost got caught!","TWN":"呼！好險！這不是差點就被發現了嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"번개 같은 접속종료였어!","JPN":"稲妻のようなログアウトだった！","ENG":"We signed out in a blink!","TWN":"閃電般的終止連線速度！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"학창 시절 몰래 게임하다가 엄마가 들어올 때 화면을 전환하던 실력이 여전한 걸, 앨버트!","JPN":"学生時代、隠れてゲームしてて母親が入ってきた瞬間、画面を切り換えてた実力が今もなお健在だな、アルバート！","ENG":"I guess you still got your reflexes from switching your computer screen when your mom walked in on you, Albert!","TWN":"我想起學生時代偷偷玩遊戲，因為媽媽進來所以快速切換螢幕的時候了，你這手法還是一如既往啊，亞伯特！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"뭐 이 정도를 가지고...... 훗.","JPN":"これくらいどうってことない……ふっ。","ENG":"This is nothing... Heh.","TWN":"這種程度算什麼……呵。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"아니, 그게 문제가 아니잖아?!","JPN":"いや、そんなのどうでもいいでしょ！？","ENG":"Hang on, that's not the issue here!","TWN":"不是，這不是重點好嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"넘버 1이 잡혀갔다고!! 그럼 이제 이 모임은 어떻게 되는 거야?","JPN":"ナンバー1が捕まったのよ？　そしたらこの集まりはどうなるわけ！？","ENG":"Number 1 has been taken into custody! What's going to become of this group now?","TWN":"NO.1被抓走了啊！！那現在這個團體怎麼辦？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"......그야 뭐 당연히.","JPN":"……それは当然。","ENG":"Well, it's obvious...","TWN":"……那當然是。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"넘버 2가 넘버 1이 되겠지.","JPN":"ナンバー2がナンバー1になるだけ。","ENG":"Number 2 will become number 1.","TWN":"NO.2成為NO.1啦。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"인정합니다. 영원한 왕은 없는 법이죠.","JPN":"賛成です。永遠の王はいませんから。","ENG":"I've got to admit it. No monarch lasts forever.","TWN":"我認同，畢竟沒有人可以是永遠的王。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"......아, 그래?","JPN":"あ……そう？","ENG":"Oh, is that right?","TWN":"……啊，是嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"......그럼 넘버 1으로서 말하는데, 조직은 이 시간부로 해산이야.","JPN":"……それじゃ、ナンバー1として言うけど。組織は今をもって解散よ。","ENG":"Then let me say this as the new number one... I'm disbanding this group, effective immediately.","TWN":"……那麼我作為NO.1宣佈，這個組織從現在起正式解散。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HACKER_NPC_NULL_BOTH","text":{"KOREA":"그럴 수가아아아아!!","JPN":"そんなああああああ！","ENG":"No wayyy!!","TWN":"怎麼會這樣啊啊啊！！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};